    "about.kicker": "About",
    "about.title": 'Like every piece of a mosaic, <span class="grad">every detail matters.</span>',
    "about.body": 'Founded in 2018, <strong>Mozaik Ofset ve Ambalaj</strong> set out with a motto of "dedication and success". With modern printing technology and an experienced team, we deliver high-quality packaging solutions for brands across food, cosmetics, textile and industry.',
    "about.c1": "Precise color management & print quality",
    "about.c2": "Short lead times, on-time delivery",
    "about.c3": "Custom box design & packaging engineering",
    "about.body2": "From concept and structural design to printing, die-cutting and finishing, everything happens under one roof — giving you tighter control, faster turnaround and consistent quality on every run, whether it is a small batch or a large order.", "about.c4": "Food-safe, BRC-certified production", "about.c5": "Free technical consultation before printing",
