    "products.title": 'A collection you <span class="grad">explore</span> as you browse',
    "products.sub": "Each design is a real Mozaik packaging model — explore it in 360° 3D.",
    "p1.t": "Offset Printing", "p1.d": "Flawless color consistency with high-resolution CMYK and Pantone printing.",
    "p2.t": "Boxes & Cartons", "p2.d": "Custom product, shipping and display boxes; durable and premium.",
    "p3.t": "Food Packaging", "p3.d": "Food-safe, durable burger and presentation boxes, branded for you.",
