    "box2.t": "Cardboard Boxes (Folding Carton)", "box2.d": "Classic folding cartons — printed, creased and shipped flat for efficiency.",
    "box3.t": "One-Point Side-Glued Folding Carton", "box3.d": "Straight-line carton glued at a single side seam — the most common tuck box.",
    "box4.t": "Two-Point Side-Glued Folding Carton", "box4.d": "Side-seam carton with two glue points for extra strength on larger boxes.",
    "box5.t": "Crash-Lock Bottom Folding Carton", "box5.d": "Auto-lock bottom that snaps into shape when opened — fast to set up, load-bearing.",
    "box6.t": "Four-Corner Glued Folding Carton", "box6.d": "Tray-style carton glued at four corners — rigid open display and product trays.",
    "box7.t": "Six-Corner Glued Folding Carton", "box7.d": "Six-corner glued build for deeper, sturdier trays and heavier contents.",
