    "box9.t": "Non-Glued Folding Carton", "box9.d": "Lock-tab carton assembled without glue — recyclable and easy to flat-pack.",
    "box10.t": "Slotter Containers", "box10.d": "Standard slotted corrugated containers — the workhorse shipping box (RSC).",
    "box11.t": "Telescope-Type Boxes", "box11.d": "Two-piece lid-and-base boxes that telescope together for a premium unboxing.",
    "box12.t": "Self-Erecting Boxes", "box12.d": "Pop-up cartons that spring open from flat — high-speed, labor-saving packing.",
    "box13.t": "Window-Patched Boxes", "box13.d": "Cartons with a clear film window so the product is visible on the shelf.",
    "box14.t": "Spot UV Boxes", "box14.d": "Selective glossy UV coating over matte — tactile contrast and premium finish.",
    "box15.t": "Hot Foil Stamping", "box15.d": "Metallic foil pressed with heat for gold/silver logos and luxury accents.",
